#!/usr/bin/env bash
# Regenerates the root index.html listing all version subdirectories.
#
# Usage: generate-index.sh <deploy_dir> <base_url>
#   deploy_dir  Root of the gh-pages deployment tree (e.g. gh-pages-deploy)
#   base_url    GitHub Pages base URL (e.g. https://connectbot.github.io/termlib)

set -euo pipefail

DEPLOY_DIR="$1"
BASE_URL="$2"

# Collect version dirs that contain an index.html, newest first.
# Tags sort numerically; "main" is listed last as the development snapshot.
mapfile -t VERSIONS < <(
    find "${DEPLOY_DIR}" -mindepth 2 -maxdepth 2 -name "index.html" \
        | sed "s|${DEPLOY_DIR}/||;s|/index.html||" \
        | sort -V -r \
        | grep -v '^main$' || true
)
# Prepend main if it exists
if [ -d "${DEPLOY_DIR}/main" ]; then
    VERSIONS=("main" "${VERSIONS[@]+"${VERSIONS[@]}"}")
fi

VERSION_ROWS=""
for v in "${VERSIONS[@]}"; do
    if [ "$v" = "main" ]; then
        LABEL="main <span class=\"platform-tag jvm-like\">snapshot</span>"
    else
        LABEL="$v"
    fi
    VERSION_ROWS+="      <div class=\"table-row table-row_platform-tagged\">
        <div>
          <div class=\"main-subrow\">
            <div><span class=\"inline-flex\"><div><a href=\"${BASE_URL}/${v}/index.html\">${LABEL}</a></div></span></div>
          </div>
        </div>
      </div>
"
done

cat > "${DEPLOY_DIR}/index.html" <<HTML
<!DOCTYPE html>
<html class="no-js" lang="en">
<head>
    <meta name="viewport" content="width=device-width, initial-scale=1" charset="UTF-8">
    <title>ConnectBot Terminal — Documentation</title>
    <link href="main/images/logo-icon.svg" rel="icon" type="image/svg">
    <script>document.documentElement.classList.replace("no-js", "js");</script>
    <script>
        const storage = localStorage.getItem("dokka-dark-mode");
        if (storage == null) {
            if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches)
                document.documentElement.classList.add("theme-dark");
        } else if (JSON.parse(storage) === true) {
            document.documentElement.classList.add("theme-dark");
        }
    </script>
    <link href="main/styles/style.css" rel="stylesheet">
    <link href="main/styles/main.css" rel="stylesheet">
    <link href="main/styles/logo-styles.css" rel="stylesheet">
    <link href="main/ui-kit/ui-kit.min.css" rel="stylesheet">
    <script src="main/ui-kit/ui-kit.min.js" defer></script>
    <style>
        .version-index { max-width: 860px; margin: 48px auto; padding: 0 24px; }
        .version-index h1 { margin-top: 0; }
    </style>
</head>
<body>
<div class="root">
    <header class="navigation theme-dark" id="navigation-wrapper" role="banner">
        <a class="library-name--link" href="${BASE_URL}/index.html" tabindex="1">ConnectBot Terminal</a>
        <div class="navigation-controls">
            <button class="navigation-controls--btn navigation-controls--btn_theme" id="theme-toggle-button" type="button">Switch theme</button>
        </div>
    </header>
    <div id="container">
        <div id="main" data-item-type="SECTION" role="main">
            <div class="main-content version-index" id="content">
                <h1 class="cover">ConnectBot Terminal</h1>
                <div class="platform-hinted UnderCoverText">
                    <div class="content">
                        <p class="paragraph">ConnectBot Terminal is a high-performance Jetpack Compose terminal emulator component for Android, providing accurate VT100/ANSI terminal emulation via libvterm.</p>
                    </div>
                </div>
                <h2>Documentation versions</h2>
                <div class="table">
${VERSION_ROWS}                </div>
            </div>
            <div class="footer">
                <div class="footer--container">
                    <a href="#content" id="go-to-top-link" class="footer--button footer--button_go-to-top"></a>
                    <div class="footer--content">
                        <div>
                            <span>Generated by </span>
                            <a class="footer--link footer--link_external" href="https://github.com/Kotlin/dokka">Dokka</a>
                            <div>Copyright Kenny Root</div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>
<script>
    document.getElementById("theme-toggle-button").addEventListener("click", () => {
        const isDark = document.documentElement.classList.toggle("theme-dark");
        localStorage.setItem("dokka-dark-mode", isDark);
    });
</script>
</body>
</html>
HTML
